import React, { useState, useEffect, useRef } from 'react';
import { useWallet } from '../contexts/WalletContext';
import { getContract, getContractReadOnly } from '../utils/contract';
import { ethers } from 'ethers';
import { 
  MessageCircle, 
  Send, 
  Plus,
  User,
  X,
  Loader,
  CheckCircle,
  AlertCircle,
  Trash2
} from 'lucide-react';

const PrivateChats = () => {
  const { walletAddress } = useWallet();
  
  // State management
  const [contacts, setContacts] = useState([]);
  const [selectedContact, setSelectedContact] = useState(null);
  const [messages, setMessages] = useState([]);
  const [newMessage, setNewMessage] = useState('');
  const [newContactAddress, setNewContactAddress] = useState('');
  const [loading, setLoading] = useState(false);
  const [sending, setSending] = useState(false);
  const [error, setError] = useState('');
  const [sendSuccess, setSendSuccess] = useState(false);
  
  // Refs
  const messagesEndRef = useRef(null);
  const eventListenerRef = useRef(null);
  
  // localStorage key for contacts
  const CONTACT_KEY = `dechat_contacts_${walletAddress}`;

  useEffect(() => {
    if (isConnected && account) {
      setWallet(account);
    }
  }, [isConnected, account, setWallet]);

  // Auto-hide toast after 3 seconds
  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const showToast = (message, type = 'success') => {
    setToast({ message, type });
  };

  const formatAddress = (address) => {
    return `${address.slice(0, 6)}...${address.slice(-4)}`;
  };

  const handleCreateChat = () => {
    setError('');

    const result = createPrivateChat(newChatAddress, account);

    if (!result.success) {
      setError(result.error);
      return;
    }

    setShowNewChatModal(false);
    setNewChatAddress('');
  };

  const handleSendMessage = async (e) => {
    e.preventDefault();
    if (newMessage.trim() && !isLoading) {
      const messageText = newMessage.trim();
      setNewMessage(''); // Clear input immediately
      
      try {
        await sendPrivateMessage(messageText);
        showToast('✅ Message sent to IPFS!', 'success');
      } catch (error) {
        showToast('❌ Failed to send message', 'error');
        setNewMessage(messageText); // Restore message on error
      }
    }
  };

  const activeChat = chats.find(chat => chat.id === activeChatId);
  const activeChatMessages = activeChat?.messages || [];

  const getOtherParticipant = (chat) => {
    if (!chat || !account) return '';
    return chat.participants.find(
      p => p.toLowerCase() !== account.toLowerCase()
    );
  };

  const isOwnMessage = (sender) => {
    return sender.toLowerCase() === account.toLowerCase();
  };

  const getMessageStatus = (message) => {
    if (!isOwnMessage(message.sender)) return null;
    
    // If message has ipfsHash, it's been uploaded to IPFS
    if (message.ipfsHash) {
      return 'sent'; // Sent to IPFS
    }
    return 'sending'; // Still uploading
  };

  const MessageStatusIcon = ({ status }) => {
    if (!status) return null;
    
    switch (status) {
      case 'sending':
        return <Clock className="w-3 h-3 ml-1 inline" />;
      case 'sent':
        return <CheckCheck className="w-3 h-3 ml-1 inline" />;
      default:
        return null;
    }
  };

  const handleLongPress = (messageId) => {
    const timer = setTimeout(() => {
      setShowDeleteMenu(messageId);
    }, 500);
    setLongPressTimer(timer);
  };

  const handlePressEnd = () => {
    if (longPressTimer) {
      clearTimeout(longPressTimer);
      setLongPressTimer(null);
    }
  };

  const handleDeleteMessage = (messageId, deleteType) => {
    deletePrivateMessage(messageId, deleteType);
    setShowDeleteMenu(null);
  };

  const handleChatSelect = (chatId) => {
    const chat = chats.find(c => c.id === chatId);
    if (chat) {
      const otherParticipant = getOtherParticipant(chat);
      createPrivateChat(otherParticipant, account);
    }
  };

  return (
    <div className="flex h-full bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
      {/* Chat List Sidebar */}
      <div className="w-80 border-r border-gray-200 flex flex-col">
        <div className="p-4 border-b border-gray-200">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-semibold text-gray-900">Private Chats</h2>
            <button
              onClick={() => setShowNewChatModal(true)}
              className="p-2 text-primary-600 hover:bg-primary-50 rounded-lg transition-colors duration-200"
            >
              <Plus className="w-5 h-5" />
            </button>
          </div>
          
          <div className="relative">
            <Search className="w-4 h-4 absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
            <input
              type="text"
              placeholder="Search chats..."
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500 focus:border-transparent"
            />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto">
          {chats.length === 0 ? (
            <div className="p-4 text-center text-gray-500">
              <p className="text-sm">No chats yet</p>
              <p className="text-xs mt-1">Click + to start a new chat</p>
            </div>
          ) : (
            chats.map((chat) => {
              const otherParticipant = getOtherParticipant(chat);
              const lastMessage = chat.messages[chat.messages.length - 1];
              
              return (
                <div
                  key={chat.id}
                  onClick={() => handleChatSelect(chat.id)}
                  className={`p-4 border-b border-gray-100 cursor-pointer hover:bg-gray-50 transition-colors duration-200 ${
                    activeChatId === chat.id ? 'bg-primary-50 border-primary-200' : ''
                  }`}
                >
                  <div className="flex items-center space-x-3 mb-2">
                    <div className="w-8 h-8 bg-primary-100 rounded-full flex items-center justify-center">
                      <User className="w-4 h-4 text-primary-600" />
                    </div>
                    <div className="flex-1">
                      <div className="flex items-center justify-between">
                        <h3 className="font-medium text-gray-900">
                          {formatAddress(otherParticipant)}
                        </h3>
                      </div>
                      {lastMessage && (
                        <>
                          <p className="text-sm text-gray-600 truncate">
                            {lastMessage.deletedForEveryone 
                              ? 'This message was deleted' 
                              : lastMessage.content}
                          </p>
                          <p className="text-xs text-gray-500 mt-1">
                            {format(new Date(lastMessage.timestamp), 'MMM d, HH:mm')}
                          </p>
                        </>
                      )}
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>
      </div>

      {/* Chat Area */}
      <div className="flex-1 flex flex-col">
        {activeChatId && activeChat ? (
          <>
            {/* Chat Header */}
            <div className="p-4 border-b border-gray-200">
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-3">
                  <div className="w-10 h-10 bg-primary-100 rounded-full flex items-center justify-center">
                    <User className="w-5 h-5 text-primary-600" />
                  </div>
                  <div>
                    <h3 className="font-semibold text-gray-900">
                      {formatAddress(getOtherParticipant(activeChat))}
                    </h3>
                    <p className="text-sm text-gray-500">
                      Private conversation
                    </p>
                  </div>
                </div>
              </div>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {activeChatMessages.length === 0 ? (
                <div className="flex items-center justify-center h-full">
                  <p className="text-gray-500">No messages yet. Start the conversation!</p>
                </div>
              ) : (
                activeChatMessages
                  .filter(message => !message.deletedForMe)
                  .map((message) => (
                    <div
                      key={message.id}
                      className={`flex ${isOwnMessage(message.sender) ? 'justify-end' : 'justify-start'}`}
                    >
                      <div className="relative group">
                        <div
                          className={`max-w-xs lg:max-w-md px-4 py-2 rounded-lg ${
                            message.deletedForEveryone
                              ? 'bg-gray-200 text-gray-500 italic'
                              : isOwnMessage(message.sender)
                              ? 'bg-primary-600 text-white'
                              : 'bg-gray-100 text-gray-900'
                          }`}
                          onMouseDown={() => isOwnMessage(message.sender) && !message.deletedForEveryone && handleLongPress(message.id)}
                          onMouseUp={handlePressEnd}
                          onMouseLeave={handlePressEnd}
                          onTouchStart={() => isOwnMessage(message.sender) && !message.deletedForEveryone && handleLongPress(message.id)}
                          onTouchEnd={handlePressEnd}
                        >
                          <p className="text-sm">{message.content}</p>
                          <p className={`text-xs mt-1 flex items-center ${
                            message.deletedForEveryone
                              ? 'text-gray-400'
                              : isOwnMessage(message.sender) ? 'text-primary-200' : 'text-gray-500'
                          }`}>
                            {format(new Date(message.timestamp), 'HH:mm')}
                            {isOwnMessage(message.sender) && (
                              <MessageStatusIcon status={getMessageStatus(message)} />
                            )}
                          </p>
                        </div>

                        {showDeleteMenu === message.id && isOwnMessage(message.sender) && (
                          <div className="absolute top-0 right-0 mt-2 mr-2 bg-white rounded-lg shadow-lg border border-gray-200 py-2 z-10">
                            <button
                              onClick={() => handleDeleteMessage(message.id, 'forMe')}
                              className="w-full px-4 py-2 text-left text-sm text-gray-700 hover:bg-gray-100 flex items-center space-x-2"
                            >
                              <Trash2 className="w-4 h-4" />
                              <span>Delete for Me</span>
                            </button>
                            <button
                              onClick={() => handleDeleteMessage(message.id, 'forEveryone')}
                              className="w-full px-4 py-2 text-left text-sm text-red-600 hover:bg-red-50 flex items-center space-x-2"
                            >
                              <Trash2 className="w-4 h-4" />
                              <span>Delete for Everyone</span>
                            </button>
                            <button
                              onClick={() => setShowDeleteMenu(null)}
                              className="w-full px-4 py-2 text-left text-sm text-gray-500 hover:bg-gray-100 flex items-center space-x-2"
                            >
                              <X className="w-4 h-4" />
                              <span>Cancel</span>
                            </button>
                          </div>
                        )}

                        {isOwnMessage(message.sender) && !message.deletedForEveryone && (
                          <button
                            onClick={() => setShowDeleteMenu(showDeleteMenu === message.id ? null : message.id)}
                            className="absolute top-1 right-1 opacity-0 group-hover:opacity-100 p-1 text-gray-400 hover:text-gray-600 transition-opacity duration-200"
                          >
                            <MoreVertical className="w-3 h-3" />
                          </button>
                        )}
                      </div>
                    </div>
                  ))
              )}
            </div>

            {showDeleteMenu && (
              <div 
                className="fixed inset-0 z-5" 
                onClick={() => setShowDeleteMenu(null)}
              />
            )}

            {/* Message Input */}
            <div className="p-4 border-t border-gray-200">
              <form onSubmit={handleSendMessage} className="flex space-x-4">
                <input
                  type="text"
                  value={newMessage}
                  onChange={(e) => setNewMessage(e.target.value)}
                  placeholder="Type your message..."
                  disabled={isLoading}
                  className="flex-1 input-field disabled:opacity-50"
                />
                <button
                  type="submit"
                  disabled={!newMessage.trim() || isLoading}
                  className="btn-primary flex items-center space-x-2 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {isLoading ? (
                    <>
                      <Loader2 className="w-4 h-4 animate-spin" />
                      <span>Sending...</span>
                    </>
                  ) : (
                    <>
                      <Send className="w-4 h-4" />
                      <span>Send</span>
                    </>
                  )}
                </button>
              </form>
            </div>
          </>
        ) : (
          <div className="flex-1 flex items-center justify-center">
            <div className="text-center">
              <MessageCircle className="w-12 h-12 text-gray-400 mx-auto mb-4" />
              <h3 className="text-lg font-medium text-gray-900 mb-2">
                Select a conversation
              </h3>
              <p className="text-gray-500">
                Choose a chat from the sidebar or start a new one
              </p>
            </div>
          </div>
        )}
      </div>

      {/* New Chat Modal */}
      {showNewChatModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-md">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">
              Start New Chat
            </h3>
            <div className="mb-4">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Wallet Address
              </label>
              <input
                type="text"
                value={newChatAddress}
                onChange={(e) => {
                  setNewChatAddress(e.target.value);
                  setError('');
                }}
                placeholder="0x..."
                className="input-field"
              />
              {error && (
                <p className="mt-2 text-sm text-red-600">{error}</p>
              )}
            </div>
            <div className="flex space-x-3">
              <button
                onClick={() => {
                  setShowNewChatModal(false);
                  setNewChatAddress('');
                  setError('');
                }}
                className="flex-1 btn-secondary"
              >
                Cancel
              </button>
              <button
                onClick={handleCreateChat}
                className="flex-1 btn-primary"
              >
                Start Chat
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Toast Notification */}
      {toast && (
        <div className="fixed bottom-4 right-4 z-50 animate-slide-up">
          <div className={`px-6 py-3 rounded-lg shadow-lg flex items-center space-x-3 ${
            toast.type === 'success' 
              ? 'bg-green-500 text-white' 
              : 'bg-red-500 text-white'
          }`}>
            {toast.type === 'success' ? (
              <CheckCheck className="w-5 h-5" />
            ) : (
              <X className="w-5 h-5" />
            )}
            <span className="font-medium">{toast.message}</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default PrivateChats;
